from flask import Flask
from flask_graphql import GraphQLView
from graphene import ObjectType, String, Schema, List
import psycopg2

app = Flask(__name__)

# Database connection
def get_db_connection():
    conn = psycopg2.connect(
        dbname='your_db_name',
        user='your_user',
        password='your_password',
        host='your_host',
        port='your_port'
    )
    return conn

class SearchResult(ObjectType):
    id = String()
    name = String()
    description = String()

class Query(ObjectType):
    search = List(SearchResult, query=String(required=True))

    def resolve_search(self, info, query):
        conn = get_db_connection()
        cur = conn.cursor()
        
        # Build dynamic SQL query
        sql_query = "SELECT id, name, description FROM your_table WHERE"
        conditions = []
        
        if query:
            conditions.append(f"name ILIKE %s")
            conditions.append(f"description ILIKE %s")
            params = [f'%{query}%', f'%{query}%']
        else:
            params = []

        sql_query += " OR ".join(conditions)
        
        cur.execute(sql_query, params)
        results = cur.fetchall()
        cur.close()
        conn.close()

        return [SearchResult(id=result[0], name=result[1], description=result[2]) for result in results]

schema = Schema(query=Query)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True
    )
)

if __name__ == '__main__':
    app.run(debug=True)